INSERT INTO questions (question_text, choices, correct_answer, explanation, subject, topic, difficulty, exam_type) VALUES
('What is the capital city of the Philippines?', '["Manila", "Cebu", "Davao", "Quezon City"]', 'A', 'Manila is the capital city of the Philippines, although Quezon City is the most populous city. Manila has been the capital since 1948.', 'Social Studies', 'Geography', 'easy', 'secondary'),
('What are the three island groups of the Philippines?', '["Luzon, Visayas, and Mindanao", "Luzon, Palawan, and Mindanao", "Luzon, Cebu, and Mindanao", "Luzon, Visayas, and Sulu"]', 'A', 'The Philippines is divided into three main island groups: Luzon (north), Visayas (central), and Mindanao (south).', 'Social Studies', 'Geography', 'easy', 'secondary'),
('What is the largest island in the Philippines?', '["Luzon", "Mindanao", "Palawan", "Cebu"]', 'A', 'Luzon is the largest island in the Philippines by area and has the highest population, containing Metro Manila and many major cities.', 'Social Studies', 'Geography', 'easy', 'secondary'),
('Who wrote the Philippine national anthem "Lupang Hinirang"?', '["Julian Felipe (music) and José Palma (lyrics)", "José Rizal", "Emilio Aguinaldo", "Andres Bonifacio"]', 'A', 'The music of "Lupang Hinirang" was composed by Julian Felipe in 1898. The lyrics were written by José Palma in 1899.', 'Social Studies', 'Philippine History', 'medium', 'secondary'),
('What is the significance of June 12, 1898 in Philippine history?', '["Philippine independence from Spain was declared", "The Philippine-American War began", "The 1987 Constitution was ratified", "The EDSA Revolution occurred"]', 'A', 'On June 12, 1898, General Emilio Aguinaldo proclaimed Philippine independence from Spanish colonial rule in Kawit, Cavite.', 'Social Studies', 'Philippine History', 'easy', 'secondary'),
('What is the term for government by the people, either directly or through elected representatives?', '["Democracy", "Monarchy", "Oligarchy", "Theocracy"]', 'A', 'Democracy is a form of government in which power is vested in the people. In a representative democracy, citizens elect officials to govern on their behalf.', 'Social Studies', 'Government', 'easy', 'secondary'),
('What is ASEAN and when was it founded?', '["Association of Southeast Asian Nations, founded in 1967", "Asian States Economic Alliance Network, founded in 1975", "Association of South and East Asian Nations, founded in 1955", "Asian Strategic Economic Alliance Network, founded in 1960"]', 'A', 'ASEAN (Association of Southeast Asian Nations) was founded on August 8, 1967 in Bangkok, Thailand by 5 founding members including the Philippines.', 'Social Studies', 'World History', 'medium', 'secondary'),
('What was World War II?', '["A global war from 1939-1945 involving Allied and Axis powers", "A war between the US and USSR in the 1950s", "A series of conflicts in Asia in the 1940s only", "A European civil war in the 1940s"]', 'A', 'World War II (1939-1945) was a global conflict involving the Allied powers (US, UK, Soviet Union, etc.) fighting against the Axis powers (Germany, Japan, Italy).', 'Social Studies', 'World History', 'easy', 'secondary'),
('What was the Cold War?', '["Political tension and indirect conflict between the US and Soviet Union after WWII", "A direct military war between the US and USSR", "A war fought in cold weather climates", "A series of trade wars between Western nations"]', 'A', 'The Cold War (1947-1991) was a period of geopolitical tension between the Western bloc (US, NATO allies) and Eastern bloc (USSR, Warsaw Pact) — not direct military conflict but competition in arms, space, and ideology.', 'Social Studies', 'World History', 'medium', 'secondary'),
('What is "sovereignty"?', '["The supreme political authority and independence of a state", "The power of the president", "The right to vote", "The ability to collect taxes"]', 'A', 'Sovereignty is the supreme authority of a state to govern itself, make laws, and operate independently without interference from external powers.', 'Social Studies', 'Government', 'medium', 'secondary'),
('What is the significance of the French Revolution (1789)?', '["It overthrew the monarchy and established principles of liberty, equality, and fraternity", "It established democracy in France permanently", "It led to French colonialism", "It created a constitutional monarchy in France"]', 'A', 'The French Revolution (1789) overthrew the French monarchy and aristocracy, establishing the principles of liberté, égalité, fraternité and inspiring democratic movements worldwide.', 'Social Studies', 'World History', 'medium', 'secondary'),
('What was the Katipunan?', '["A secret revolutionary organization founded by Andres Bonifacio to fight Spanish colonization", "A religious organization during Spanish colonization", "A Filipino political party during American colonization", "A cultural organization preserving Filipino traditions"]', 'A', 'The Katipunan (Kataas-taasang, Kagalang-galangang Katipunan ng mga Anak ng Bayan) was founded by Andres Bonifacio in 1892 to overthrow Spanish rule through armed revolution.', 'Social Studies', 'Philippine History', 'easy', 'secondary'),
('What is the UN (United Nations)?', '["An international organization founded in 1945 to promote peace, security, and cooperation", "A military alliance led by the United States", "A trade organization for developed nations", "A World Bank subsidiary for development aid"]', 'A', 'The United Nations was founded in 1945 after WWII to maintain international peace and security, develop friendly relations among nations, and promote social progress.', 'Social Studies', 'World History', 'easy', 'secondary'),
('Who was José Rizal?', '["Philippine national hero, writer of Noli Me Tangere and El Filibusterismo", "Founder of the Katipunan and leader of Philippine Revolution", "First President of the Philippine Commonwealth", "Filipino general who defeated Spanish forces"]', 'A', 'José Rizal (1861-1896) is the Philippine national hero. He was a writer, doctor, and reformist whose novels Noli Me Tangere and El Filibusterismo ignited Philippine nationalism.', 'Social Studies', 'Philippine History', 'easy', 'secondary'),
('What is "human rights"?', '["Rights inherent to all human beings, regardless of nationality, sex, religion, or status", "Rights granted by the government only", "Rights only for citizens of democratic countries", "Rights that can be taken away by authorities"]', 'A', 'Human rights are universal rights that every person is entitled to regardless of nationality, ethnicity, religion, or other status. They include civil, political, economic, social, and cultural rights.', 'Social Studies', 'Government', 'easy', 'secondary'),
('What was the Industrial Revolution?', '["A period of rapid industrialization beginning in 18th-century Britain", "A political revolution in industrial cities", "A workers'' uprising against factory owners", "A technological revolution in the 21st century"]', 'A', 'The Industrial Revolution (c.1760s-1840s) began in Britain, transforming economies from agricultural to manufacturing-based through the development of factories, steam engines, and mass production.', 'Social Studies', 'World History', 'medium', 'secondary'),
('What is "nationalism"?', '["Identification with and pride in one''s nation, often with desire for political independence", "The belief in world government", "Opposition to all forms of government", "The economic policy of protectionism"]', 'A', 'Nationalism is a political ideology centered on the belief that people sharing a common identity, culture, or history should form their own sovereign nation.', 'Social Studies', 'World History', 'medium', 'secondary'),
('What is the function of the barangay captain (punong barangay)?', '["To lead the barangay''s legislative body and implement national and local laws", "To enforce criminal law only", "To collect national taxes", "To appoint barangay officials"]', 'A', 'The Punong Barangay is the chief executive of the barangay, presiding over the Sangguniang Barangay (legislative body) and implementing laws and ordinances at the community level.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What was the significance of the EDSA People Power Revolution in 1986?', '["It peacefully overthrew the Marcos dictatorship and restored democracy in the Philippines", "It established a new constitution for the Philippines", "It declared independence from American influence", "It ended the Philippine-American War"]', 'A', 'The 1986 EDSA People Power Revolution was a peaceful, non-violent uprising that removed President Ferdinand Marcos from power after 20 years, restoring democracy under President Corazon Aquino.', 'Social Studies', 'Philippine History', 'easy', 'secondary'),
('What was colonialism?', '["A policy of extending a nation''s rule over other territories by settlement or economic control", "A form of democracy", "A trade agreement between nations", "A military alliance between colonial nations"]', 'A', 'Colonialism is the practice of acquiring and maintaining colonies — typically by conquest — to exploit their resources and labor, and imposing political, economic, and cultural control.', 'Social Studies', 'World History', 'medium', 'secondary'),
('What is the role of the Supreme Court in Philippine government?', '["The highest judicial authority that interprets laws and the Constitution", "The body that makes laws", "The office that implements laws", "The body that elects the President"]', 'A', 'The Supreme Court is the highest court in the Philippines, with power of judicial review to interpret the Constitution and laws, and to declare laws unconstitutional.', 'Social Studies', 'Philippine Government', 'easy', 'secondary'),
('Who was Andres Bonifacio?', '["Founder of the Katipunan and leader of the Philippine Revolution against Spain", "National hero who wrote Noli Me Tangere", "First President of the Philippine Republic", "Leader of Filipino forces against American colonizers"]', 'A', 'Andres Bonifacio (1863-1897) was a Filipino nationalist and revolutionary leader who founded the Katipunan and led the armed revolution against Spanish colonial rule. He is the "Father of the Philippine Revolution."', 'Social Studies', 'Philippine History', 'easy', 'secondary'),
('What were the causes of World War I?', '["Militarism, alliances, imperialism, nationalism (MAIN), and the assassination of Archduke Franz Ferdinand", "Territorial disputes between France and Germany", "Economic competition between the US and Europe", "Russian Revolution and rise of communism"]', 'A', 'WWI was caused by MAIN factors: Militarism, Alliances (Triple Alliance vs. Triple Entente), Imperialism, Nationalism, plus the immediate trigger of Archduke Franz Ferdinand''s assassination in 1914.', 'Social Studies', 'World History', 'medium', 'secondary'),
('What is the "Magna Carta"?', '["A 1215 English document that limited royal power and established rights of the nobility", "The first democratic constitution", "A declaration of independence from Roman rule", "The first human rights document in the modern era"]', 'A', 'The Magna Carta (1215) was a charter signed by King John of England, limiting the power of the monarchy and establishing certain legal rights — a foundation for constitutional government.', 'Social Studies', 'World History', 'hard', 'secondary'),
('What is the Philippine Overseas Workers'' Act (Republic Act 8042)?', '["A law protecting the rights and welfare of Overseas Filipino Workers (OFWs)", "A law regulating domestic workers", "A law managing immigration", "A law governing maritime workers"]', 'A', 'Republic Act 8042 (Migrant Workers and Overseas Filipinos Act) protects the rights of OFWs and promotes their welfare. It was later strengthened by RA 10022.', 'Social Studies', 'Philippine Government', 'hard', 'secondary'),
('What is the significance of the Universal Declaration of Human Rights (UDHR)?', '["A 1948 UN document declaring the fundamental rights of all human beings", "A military treaty after WWII", "A trade agreement between nations", "A constitution for the United Nations"]', 'A', 'The UDHR was adopted by the UN General Assembly on December 10, 1948, declaring the fundamental civil, political, economic, social, and cultural rights of all people worldwide.', 'Social Studies', 'World History', 'medium', 'secondary'),
('What was Martial Law under Ferdinand Marcos?', '["A period (1972-1981) when Marcos suspended civil rights and ruled by decree", "A period of military rule when the army replaced the president", "A military alliance with the United States", "A period of emergency response to natural disasters"]', 'A', 'Ferdinand Marcos declared Martial Law in September 1972, suspending the writ of habeas corpus, imposing curfews, arresting opposition figures, and ruling by decree until 1981.', 'Social Studies', 'Philippine History', 'medium', 'secondary'),
('What is the "separation of Church and State" in the Philippines?', '["The government cannot establish a state religion or interfere with religious freedom", "Religious leaders cannot vote", "Churches cannot own property", "Religious education is banned in public schools"]', 'A', 'Section 6, Article II of the 1987 Constitution: "The separation of Church and State shall be inviolable." The state neither supports nor persecutes any religion.', 'Social Studies', 'Philippine Government', 'medium', 'secondary'),
('What was the role of Emilio Aguinaldo in Philippine history?', '["He was the first President of the Philippine Republic (1899) and led forces against Spain and America", "He wrote the Philippine Constitution", "He founded the Katipunan", "He was a Spanish colonial governor who supported Filipino independence"]', 'A', 'Emilio Aguinaldo was the first President of the Philippine Republic (Malolos Republic, 1899), who led Philippine forces against Spain during the Revolution and against the United States during the Philippine-American War.', 'Social Studies', 'Philippine History', 'medium', 'secondary'),
('What were the effects of Spanish colonization on the Philippines?', '["Christianity, Spanish language influence, changes to political and social structure, land system changes", "Economic development and industrialization", "Introduction of democratic government", "Cultural preservation of pre-colonial traditions"]', 'A', 'Spanish colonization (1565-1898) brought Christianity, Spanish language influence, the encomienda land system, centralized government, and dramatic changes to Philippine society and culture.', 'Social Studies', 'Philippine History', 'medium', 'secondary'),
('What is "geopolitics"?', '["The study of how geography influences politics and international relations", "The politics of local government units", "Economic policy of a nation", "Military strategy in warfare"]', 'A', 'Geopolitics studies the influence of geographic factors (location, natural resources, territory) on political power, international relations, and foreign policy decisions.', 'Social Studies', 'World History', 'hard', 'secondary'),
('What was the Philippine-American War?', '["A conflict (1899-1902) between the Philippines and the US after the US acquired the Philippines from Spain", "A war in the 1940s between Filipino and American forces", "A colonial dispute between Spain and the US over the Philippines", "A war that resulted in Philippine independence from the US"]', 'A', 'The Philippine-American War (1899-1902) was fought after the US acquired the Philippines from Spain via the Treaty of Paris (1898) for $20 million. Filipino forces, led by Aguinaldo, fought American annexation.', 'Social Studies', 'Philippine History', 'medium', 'secondary'),
('What is the right of "suffrage"?', '["The right to vote in elections", "The right to free speech", "The right to own property", "The right to peaceful assembly"]', 'A', 'Suffrage is the right to vote in public elections. In the Philippines, all citizens 18 years of age and above who have resided in the Philippines for at least one year may vote.', 'Social Studies', 'Philippine Government', 'easy', 'secondary'),
('What is "imperialism"?', '["A policy where a strong nation extends power over weaker nations economically, politically, or militarily", "The study of empires in history", "A policy of international trade", "A form of democratic government"]', 'A', 'Imperialism is a policy of extending a nation''s power and influence over other nations through military force, economic domination, or political control — characteristic of 19th-century European expansion.', 'Social Studies', 'World History', 'medium', 'secondary'),
('What was the significance of the Malolos Constitution (1899)?', '["It was the first Philippine constitution, establishing the First Philippine Republic", "It was the constitution under American colonization", "It was created by the 1987 Constitutional Commission", "It was a Spanish-imposed constitution for the Philippines"]', 'A', 'The Malolos Constitution (1899) was the first Philippine constitution, creating the First Philippine Republic under President Emilio Aguinaldo. It was a liberal, democratic document.', 'Social Studies', 'Philippine History', 'hard', 'secondary'),
('What is the "United Nations'' Sustainable Development Goals" (SDGs)?', '["17 global goals adopted in 2015 to end poverty, protect the planet, and ensure prosperity by 2030", "Goals set by developed nations for economic growth", "Military goals for global security", "Trade goals for reducing tariffs by 2030"]', 'A', 'The 17 SDGs were adopted by the UN in 2015 as a universal call to action to end poverty, protect the planet, and ensure peace and prosperity for all people by 2030.', 'Social Studies', 'World History', 'medium', 'secondary'),
('Who was the first woman President of the Philippines?', '["Corazon Aquino", "Gloria Macapagal-Arroyo", "Imelda Marcos", "Miriam Defensor-Santiago"]', 'A', 'Corazon "Cory" Aquino became the 11th President of the Philippines (1986-1992) — the first woman president — after the 1986 EDSA People Power Revolution that ended the Marcos dictatorship.', 'Social Studies', 'Philippine History', 'easy', 'secondary'),
('What is the concept of "rule of law"?', '["All persons and institutions are accountable to laws applied fairly and impartially", "The government can make any law it wants", "Powerful people are exempt from laws", "Laws only apply to criminals"]', 'A', 'The rule of law means that all people and institutions (including the government itself) are subject to and accountable to the law, applied fairly and equally.', 'Social Studies', 'Government', 'medium', 'secondary'),
('What was the Renaissance?', '["A European cultural and intellectual movement (14th-17th century) that revived classical learning and humanist ideas", "A period of religious reform in Europe", "The beginning of European democracy", "A technological revolution in medieval Europe"]', 'A', 'The Renaissance (14th-17th centuries) was a cultural movement originating in Italy that emphasized classical learning, humanism, art, literature, and science, marking the transition from medieval to modern era.', 'Social Studies', 'World History', 'medium', 'secondary'),
('What is "civil society"?', '["Non-governmental organizations, community groups, and associations that operate independently of the state", "Government-owned enterprises", "Political parties and government agencies", "The military and police force"]', 'A', 'Civil society includes non-governmental organizations (NGOs), community groups, trade unions, religious organizations, and other voluntary associations that operate between individuals and the state.', 'Social Studies', 'Government', 'hard', 'secondary'),
('What is the importance of the Treaty of Paris (1898) to Philippine history?', '["Spain ceded the Philippines to the United States for $20 million, ending Spanish colonial rule but beginning American colonization", "The Philippines was given full independence", "The Philippines was returned to Spain after a brief American presence", "It established the Philippine Republic"]', 'A', 'The Treaty of Paris (December 10, 1898) ended the Spanish-American War. Spain ceded the Philippines, Cuba, and Puerto Rico to the US. The Philippines was sold for $20 million, beginning American colonial rule.', 'Social Studies', 'Philippine History', 'medium', 'secondary'),
('What is the "social contract" theory?', '["The idea that citizens consent to give up certain freedoms to a government in exchange for protection and order", "A formal written agreement between all citizens", "The economic contract between workers and employers", "An international agreement between nations"]', 'A', 'Social contract theory (Locke, Hobbes, Rousseau) proposes that individuals surrender some freedoms to a governing authority in exchange for social order, security, and protection of remaining rights.', 'Social Studies', 'Government', 'hard', 'secondary'),
('What was the Bataan Death March?', '["The forced march of Filipino and American POWs by Japanese forces in 1942", "A march of Filipino revolutionaries against Spain", "A military retreat during the Philippine Revolution", "A protest march during Martial Law"]', 'A', 'The Bataan Death March (April 1942) was a 65-mile forced march of about 75,000 Filipino and American prisoners of war by Japanese forces, resulting in thousands of deaths from brutality, starvation, and disease.', 'Social Studies', 'Philippine History', 'medium', 'secondary'),
('What is the "Bill of Rights" in a democratic government?', '["A list of fundamental rights and freedoms guaranteed to citizens", "A bill of expenses in the national budget", "A list of laws passed by Congress", "A document listing citizen responsibilities"]', 'A', 'A Bill of Rights is a formal declaration of the fundamental rights and freedoms of citizens that the government cannot infringe upon (e.g., freedom of speech, religion, assembly, due process).', 'Social Studies', 'Government', 'easy', 'secondary'),
('What is "globalization"?', '["The process of increasing interconnection and interdependence of world economies, cultures, and governments", "The colonization of developing countries by developed nations", "A policy of economic protectionism", "The expansion of a single nation''s culture worldwide"]', 'A', 'Globalization refers to the increasing economic, cultural, and political interconnectedness of countries through trade, technology, communication, and migration.', 'Social Studies', 'World History', 'medium', 'secondary'),
('What is the Philippine Anti-Graft and Corrupt Practices Act?', '["Republic Act 3019, which prohibits corrupt practices by government officials", "Republic Act 7160, the Local Government Code", "Republic Act 9160, the Anti-Money Laundering Act", "Republic Act 6713, the Code of Conduct for Government Officials"]', 'A', 'RA 3019 (Anti-Graft and Corrupt Practices Act, 1960) prohibits public officials from receiving gifts, engaging in private business conflicting with public duties, or acting in a corrupt manner.', 'Social Studies', 'Philippine Government', 'hard', 'secondary'),
('What is the role of the Department of Education (DepEd) in the Philippines?', '["To formulate and implement policies and programs for basic education (K-12)", "To manage state universities and colleges", "To provide scholarships for college students", "To regulate private schools only"]', 'A', 'The Department of Education (DepEd) is responsible for managing and governing basic education in the Philippines (K-12), formulating policies, standards, and programs for the education sector.', 'Social Studies', 'Philippine Government', 'easy', 'secondary'),
('What is the primary source of law in a democratic republic?', '["The Constitution", "Executive orders of the President", "Decisions of the Supreme Court only", "International treaties"]', 'A', 'In a democratic republic, the Constitution is the supreme law — all other laws (statutes, executive orders, ordinances) must conform to it.', 'Social Studies', 'Government', 'easy', 'secondary'),
('What is the significance of the Cory Aquino administration (1986-1992)?', '["Restoration of democracy, 1987 Constitution ratification, and dismantling of Marcos-era authoritarian structures", "Economic miracle that lifted millions from poverty", "Establishment of the Philippine Republic", "Creation of ASEAN"]', 'A', 'The Aquino administration restored democratic institutions, ratified the 1987 Constitution, released political prisoners, restored press freedom, and dismantled many structures of the Marcos dictatorship.', 'Social Studies', 'Philippine History', 'medium', 'secondary'),
('What does the term "federalism" mean?', '["A system where power is divided between a central government and regional/state governments", "A government where one person holds all power", "A government system with no local authorities", "A democratic system where all citizens vote on every law"]', 'A', 'Federalism divides governmental authority between a national/federal government and sub-national units (states, provinces). Each level has specific powers and responsibilities.', 'Social Studies', 'Government', 'medium', 'secondary'),
('What was the significance of Lapu-Lapu in Philippine history?', '["He was the first Filipino to resist foreign colonization, killing Ferdinand Magellan in the Battle of Mactan (1521)", "He was the first Filipino president", "He founded the first Filipino state", "He was a Spanish colonial governor who promoted Filipino rights"]', 'A', 'Lapu-Lapu, chieftain of Mactan, defeated the Spanish explorer Ferdinand Magellan in the Battle of Mactan on April 27, 1521. He is celebrated as the first Filipino to resist foreign colonization.', 'Social Studies', 'Philippine History', 'easy', 'secondary');
